    ```java
import java.util.*;
public class Solution {
    public int findKthNumber(int n, int k) {
        List<Integer> nums = new ArrayList<>();
        for (int i = 1; i <= n; i++) {
            nums.add(i);
        }
        nums.sort((a, b) -> String.valueOf(a).compareTo(String.valueOf(b)));
        return nums.get(k - 1);
    }
}
```


